}


# ----- bundled: 11-Power.ps1 -----
# ============================================================================
#  Module 11 - Power tweaks  (Desktop on AC only)
#  Latency/throughput power settings that HURT laptops/battery, so they are
#  applied ONLY on a desktop running on AC. Applied to the active power scheme
#  (the Ultimate Performance plan set in module 05), so -Revert removes them
#  together with that plan (reset to Balanced).
# ============================================================================

function Invoke-Module-Power {
    Write-Log '=== Module: Power tweaks (Desktop/AC only) ===' 'STEP'

    Get-Sel01PowerInfo
    if ($Global:Sel01Tweaker.IsLaptop -or $Global:Sel01Tweaker.OnBattery) {
        Write-Log ("Laptop={0} Akku={1} -> Power-Tweaks uebersprungen (geraete-/akku-sicher)" -f `
            $Global:Sel01Tweaker.IsLaptop, $Global:Sel01Tweaker.OnBattery) 'WARN'
        return
    }

    # GUIDs: USB selective suspend setting, PCIe ASPM setting.
    $usbSub = '2a737441-1930-4402-8d77-b2bebba308a3'; $usbSet = '48e6b7a6-50f5-4782-a5d4-53bb8f07e226'
    $pciSub = '501a4d13-42af-4429-9fd1-a8218c268e20'; $pciSet = 'ee12f906-d277-404b-b6da-e5fa1a576df5'
    if ($Global:Sel01Tweaker.DryRun) {
        Write-Log 'DRYRUN: USB selective suspend off, PCIe ASPM off, disk-timeout 0 (AC)' 'INFO'
    } else {
      try {
        powercfg /SETACVALUEINDEX SCHEME_CURRENT $usbSub $usbSet 0 2>$null | Out-Null   # USB suspend off
        powercfg /SETACVALUEINDEX SCHEME_CURRENT $pciSub $pciSet 0 2>$null | Out-Null   # PCIe ASPM off
        powercfg /change disk-timeout-ac 0 2>$null | Out-Null                            # disk never sleeps
        powercfg /SETACTIVE SCHEME_CURRENT 2>$null | Out-Null
        Write-Log 'USB selective suspend off, PCIe ASPM off, disk no-sleep (AC)' 'OK'
        Add-Change 'Power: USB-suspend/PCIe-ASPM off, disk no-sleep (Desktop/AC)'
        Write-Log 'Revert: entfernt sich mit dem Power-Plan (-Revert setzt auf Balanced).' 'INFO'
      } catch {
        Write-Log "Power tweaks failed: $($_.Exception.Message)" 'WARN'
      }
    }

    # --- CPU power throttling off (Desktop/AC only - raises idle power so it
    #     is correctly gated by the laptop/battery guard above). Reversible. --
    Set-Reg 'HKLM:\SYSTEM\CurrentControlSet\Control\Power\PowerThrottling' 'PowerThrottlingOff' DWord 1 -Note 'CPU power throttling off (Desktop/AC)'
    $Global:Sel01Tweaker.RebootNeeded = $true

    # --- Opt-in: Win11 global timer resolution (fixes micro-stutter) -----
    if ($Global:Sel01Tweaker.TimerFix) {
        if ($Global:Sel01Tweaker.IsWin11) {
            Set-Reg 'HKLM:\SYSTEM\CurrentControlSet\Control\Session Manager\kernel' 'GlobalTimerResolutionRequests' DWord 1 -Note 'Win11 global timer resolution (opt-in)'
            $Global:Sel01Tweaker.RebootNeeded = $true
        } else { Write-Log 'TimerFix uebersprungen (nur Win11)' 'INFO' }
    }

    # --- Opt-in: GPU MSI mode (lower interrupt latency) ------------------
    if ($Global:Sel01Tweaker.MsiMode) {
        try {
            $gpu = Get-PnpDevice -Class Display -Status OK -ErrorAction Stop | Select-Object -First 1
            if ($gpu) {
                $path = "HKLM:\SYSTEM\CurrentControlSet\Enum\$($gpu.InstanceId)\Device Parameters\Interrupt Management\MessageSignaledInterruptProperties"
                Set-Reg $path 'MSISupported' DWord 1 -Note ("GPU MSI mode on ({0})" -f $gpu.FriendlyName)
                $Global:Sel01Tweaker.RebootNeeded = $true
            } else { Write-Log 'MSI mode: keine aktive GPU gefunden' 'WARN' }
        } catch { Write-Log "MSI mode: GPU-Erkennung fehlgeschlagen: $($_.Exception.Message)" 'WARN' }
    }
}


# ----- bundled: 12-Cleaner.ps1 -----
# ============================================================================
#  Module 12 - Temp / Disk cleaner  (both profiles, -SkipClean to skip)
#  Deletes only well-known throwaway locations (user/Windows temp, Windows
#  Update download cache, thumbnail cache) + empties the Recycle Bin. Reports
#  freed space. Not registry/revertable - it's a cleaner; only safe temp paths.
# ============================================================================

function Get-PathSizeBytes {
    param([string]$Path)
    if (-not (Test-Path $Path)) { return 0 }
    try {
        return ((Get-ChildItem -Path $Path -Recurse -Force -ErrorAction SilentlyContinue |
                 Measure-Object -Property Length -Sum).Sum)
    } catch { return 0 }
}

function Invoke-Module-Cleaner {
    Write-Log '=== Module: Temp / Disk cleaner ===' 'STEP'

    $targets = @(
        $env:TEMP,
        (Join-Path $env:windir 'Temp'),
        (Join-Path $env:windir 'SoftwareDistribution\Download'),
        (Join-Path $env:LOCALAPPDATA 'Temp'),
        (Join-Path $env:LOCALAPPDATA 'Microsoft\Windows\Explorer')   # thumbcache_*.db
    ) | Select-Object -Unique

    $freed = 0.0
    foreach ($t in $targets) {
        if (-not (Test-Path $t)) { continue }
        $thumbs = ($t -like '*\Explorer')
        $size = if ($thumbs) {
            (Get-ChildItem $t -Filter 'thumbcache_*.db' -Force -ErrorAction SilentlyContinue | Measure-Object Length -Sum).Sum
        } else { Get-PathSizeBytes $t }
        if (-not $size) { continue }

        if ($Global:Sel01Tweaker.DryRun) {
            Write-Log ("DRYRUN clean {0} (~{1} MB)" -f $t, [math]::Round($size/1MB,1)) 'INFO'
            $freed += $size; continue
        }

        $items = if ($thumbs) {
            Get-ChildItem $t -Filter 'thumbcache_*.db' -Force -ErrorAction SilentlyContinue
        } else { Get-ChildItem $t -Force -ErrorAction SilentlyContinue }
        foreach ($i in $items) {
            try { Remove-Item $i.FullName -Recurse -Force -ErrorAction Stop } catch {}   # skip in-use
        }
        $freed += $size
        Write-Log ("cleaned {0} (~{1} MB)" -f $t, [math]::Round($size/1MB,1)) 'INFO'
    }

    # Recycle Bin
    if ($Global:Sel01Tweaker.DryRun) {
        Write-Log 'DRYRUN empty recycle bin' 'INFO'
    } else {
        try { Clear-RecycleBin -Force -ErrorAction Stop; Write-Log 'recycle bin emptied' 'INFO' } catch {}
    }

    $mb = [math]::Round($freed/1MB, 1)
    Write-Log ("Cleaner: ~{0} MB Temp/Cache freigegeben" -f $mb) 'OK'
    Add-Change ("Temp/Disk geleert (~$mb MB)")
}


# ----- bundled: 13-Network.ps1 -----
# ============================================================================
#  Module 13 - Network / Latency  (Gaming profile only)
#  Disables Nagle's algorithm per active NIC (lower small-packet latency for
#  games). Every write goes through Set-Reg -> snapshotted -> reversible.
# ============================================================================

function Invoke-Module-Network {
    Write-Log '=== Module: Network / Latency (Nagle off) ===' 'STEP'

    if ($Global:Sel01Tweaker.Profile -ne 'Gaming') {
        Write-Log 'Network-Tweaks nur im Gaming-Profil, skip' 'INFO'; return
    }
    $base = 'HKLM:\SYSTEM\CurrentControlSet\Services\Tcpip\Parameters\Interfaces'
    if (-not (Test-Path $base)) { Write-Log 'Tcpip Interfaces fehlt, skip' 'WARN'; return }

    Get-ChildItem $base -ErrorAction SilentlyContinue | ForEach-Object {
        $guid = $_.PSChildName
        if ($guid -notmatch '^\{[0-9a-fA-F-]+\}$') { return }   # skip non-GUID keys (e.g. "*")
        $path = Join-Path $base $guid
        $props = Get-ItemProperty -Path $path -ErrorAction SilentlyContinue
        $dhcp  = "$($props.DhcpIPAddress)"
        $stat  = "$($props.IPAddress)"
        $hasIp = ($dhcp -and $dhcp -ne '0.0.0.0') -or ($stat -and $stat -ne '0.0.0.0')
        if ($hasIp) {
            Set-Reg $path 'TcpAckFrequency' DWord 1 -Note "Nagle off (TcpAckFrequency) auf $guid"
            Set-Reg $path 'TCPNoDelay'      DWord 1
        }
    }
}


# ----- bundled: 14-Gpu.ps1 -----
# ============================================================================
#  Module 14 - GPU telemetry  (NVIDIA + AMD; only the detected vendor runs)
#  Disables vendor telemetry/diagnostic scheduled tasks via Disable-Task
#  (recorded for -Revert) and sets documented telemetry opt-out reg flags.
#  Drivers are never touched (no repack). Driver auto-update tasks are left
#  alone (disabling updates would weaken security). Tasks tied to overclock /
#  fan curves / autostart of the control panel are deliberately NOT touched.
# ============================================================================

function Get-Sel01GpuVendors {
    <#  Returns a set of vendor strings present: 'NVIDIA' and/or 'AMD'.  #>
    $v = @()
    try {
        $names = Get-CimInstance Win32_VideoController -ErrorAction Stop | ForEach-Object { $_.Name }
        if ($names -match 'NVIDIA')          { $v += 'NVIDIA' }
        if ($names -match 'AMD|Radeon|ATI')  { $v += 'AMD' }
    } catch {}
    return ($v | Sort-Object -Unique)
}

function Disable-Sel01GpuTasks {
    <#  Disables scheduled tasks whose name matches any of the given patterns.
        Returns the count disabled. Honours DryRun via Disable-Task.  #>
    param([string[]]$Patterns)
    $hits = @()
    try {
        $csv = schtasks /Query /FO CSV /NH 2>$null
        foreach ($row in $csv) {
            if (-not $row) { continue }
            $name = ($row -split '","')[0].Trim('"').Trim()
            if (-not $name -or $name -eq 'TaskName') { continue }
            foreach ($pat in $Patterns) { if ($name -like "*$pat*") { $hits += $name; break } }
        }
    } catch { Write-Log "Task-Liste fehlgeschlagen: $($_.Exception.Message)" 'WARN' }
    $hits = $hits | Sort-Object -Unique
    foreach ($t in $hits) { Disable-Task $t }
    return $hits.Count
}

function Invoke-Module-Gpu {
    Write-Log '=== Module: GPU-Telemetrie (NVIDIA / AMD) ===' 'STEP'

    $vendors = Get-Sel01GpuVendors
    if (-not $vendors) { Write-Log 'Keine NVIDIA/AMD-GPU erkannt, skip' 'INFO'; return }

    # ---------------- NVIDIA ----------------
    if ($vendors -contains 'NVIDIA') {
        Write-Log 'NVIDIA erkannt' 'INFO'
        $n = Disable-Sel01GpuTasks -Patterns @('NvTmRep','NvTmMon','NvProfileUpdater','NvBackend','GFExperience')
        if ($n -eq 0) { Write-Log 'Keine klassischen NVIDIA-Telemetrie-Tasks (modernes NVIDIA App?)' 'INFO' }
        # Documented "do not participate" RIDs. Harmless if client absent
        # (Set-Reg creates the value; -Revert removes it again).
        $fts = 'HKLM:\SOFTWARE\NVIDIA Corporation\Global\FTS'
        Set-Reg $fts 'EnableRID44231' DWord 0 -Note 'NVIDIA telemetry opt-out (RID44231)'
        Set-Reg $fts 'EnableRID64640' DWord 0
        Set-Reg $fts 'EnableRID66610' DWord 0
    }

    # ---------------- AMD -------------------
    if ($vendors -contains 'AMD') {
        Write-Log 'AMD/Radeon erkannt' 'INFO'
        # Telemetry/diagnostic/auto-update tasks only. NOT 'StartCN' (Radeon
        # autostart) so fan curves / overclock profiles at boot keep working.
        $n = Disable-Sel01GpuTasks -Patterns @('AMD*Telemetry','AMD Crash','AMDLink','AMDInstallLauncher','AMDRyzenMasterSDK')
        if ($n -eq 0) { Write-Log 'Keine AMD-Telemetrie-/Update-Tasks gefunden' 'INFO' }
        # AMD "User Experience / Survey" opt-out (Radeon Software). Reversible;
        # harmless if the keys do not apply to the installed version.
        Set-Reg 'HKCU:\SOFTWARE\AMD\CN' 'UserExperienceProgram' DWord 0 -Note 'AMD User-Experience telemetry opt-out'
        Set-Reg 'HKCU:\SOFTWARE\AMD\CN' 'OnlineSurvey'          DWord 0
    }
}


# ----- bundled: 15-Features.ps1 -----
# ============================================================================
#  Module 15 - Optional Features / Capabilities  (lean + hardening)
#  Turns off legacy/unused Windows optional features and capabilities via DISM
#  (Disable-Sel01Feature / Remove-Sel01Capability record what they touch so
#  -Revert re-enables/re-adds them). DISM changes need a reboot to finalise.
#  Research-vetted, gaming-safe; never touches anything a game/launcher needs.
# ============================================================================

function Invoke-Module-Features {
    Write-Log '=== Module: Optional Features / Capabilities (lean) ===' 'STEP'

    if ($Global:Sel01Tweaker.DryRun) {
        Write-Log 'DRYRUN: would disable legacy optional features + niche capabilities' 'INFO'
        return
    }

    $clean = ($Global:Sel01Tweaker.Profile -eq 'Clean')

    # --- Optional features (both profiles): legacy / unused / hardening ---
    # SMB1 (wormable, WannaCry vector) + PSv2 (downgrade/AMSI-bypass vector) are
    # security hardening, not weakening. Disable-Sel01Feature skips absent/already-off.
    foreach ($f in 'SMB1Protocol','MicrosoftWindowsPowerShellV2Root','Printing-XPSServices-Features',
                    'FaxServicesClientPackage','WorkFolders-Client','MSRDC-Infrastructure') {
        Disable-Sel01Feature $f
    }

    if ($clean) {
        # Internet (IPP/HTTP) printing - LAN/USB printing unaffected; SMB Direct
        # (RDMA) - no-op on consumer NICs.
        foreach ($f in 'Printing-Foundation-InternetPrinting-Client','SmbDirect') {
            Disable-Sel01Feature $f
        }
    }

    # --- Capabilities (FoD): niche, deprecated -----------------------------
    # Fetch the (slow) capability list once, then remove by prefix.
    try {
        $caps = Get-WindowsCapability -Online -ErrorAction Stop
        Remove-Sel01Capability 'MathRecognizer'    -InstalledCaps $caps
        Remove-Sel01Capability 'App.StepsRecorder' -InstalledCaps $caps
    } catch {
        Write-Log "capability enumeration failed: $($_.Exception.Message)" 'WARN'
    }

    Add-Change 'Legacy optional features + niche capabilities removed (reboot to finalise)'
}


# ----- bundled: 16-AppxBloat.ps1 -----
# ============================================================================
#  Module 16 - App-Bloat (NATIVE appx removal, download-independent)
#  Removes pre-installed Store apps that auto-start / sync / fetch in the
#  background (Teams, new Outlook, Phone Link, Cortana, Bing apps, ...) by name -
#  works even when the Win11Debloat download was skipped (offline). Appx removal
#  is debloat-style and NOT restored by -Revert (reinstall from the Store).
#  GAMING keeps Game Bar + Gaming App; those go only in the Clean profile.
# ============================================================================

function Remove-Sel01Appx {
    param([Parameter(Mandatory)][string]$Name)
    if ($Global:Sel01Tweaker.DryRun) { Write-Log "DRYRUN appx remove: $Name" 'INFO'; return }
    try {
        $p = Get-AppxPackage -AllUsers -Name $Name -ErrorAction SilentlyContinue
        if ($p) {
            $p | Remove-AppxPackage -AllUsers -ErrorAction SilentlyContinue
            Write-Log "appx removed: $Name" 'INFO'
            Add-Change "App entfernt: $Name"
        }
        Get-AppxProvisionedPackage -Online -ErrorAction SilentlyContinue |
            Where-Object { $_.DisplayName -eq $Name } |
            ForEach-Object { Remove-AppxProvisionedPackage -Online -PackageName $_.PackageName -AllUsers -ErrorAction SilentlyContinue | Out-Null }
    } catch { Write-Log "appx remove failed: $Name -> $($_.Exception.Message)" 'WARN' }
}

function Invoke-Module-AppxBloat {
    Write-Log '=== Module: App-Bloat entfernen (nativ) ===' 'STEP'

    # Both profiles: background processes / auto-start first.
    $both = @(
        'Microsoft.YourPhone','Microsoft.OutlookForWindows','MSTeams','MicrosoftTeams',
        'Microsoft.549981C3F5F4','Microsoft.Windows.DevHome','Microsoft.PowerAutomateDesktop',
        'Microsoft.BingSearch','Microsoft.BingNews','Microsoft.BingWeather','Microsoft.MicrosoftOfficeHub',
        'Microsoft.People','Microsoft.Todos','Microsoft.GetHelp','Microsoft.WindowsFeedbackHub',
        'Microsoft.WindowsMaps','MicrosoftCorporationII.QuickAssist','MicrosoftCorporationII.MicrosoftFamily',
        'Clipchamp.Clipchamp','Microsoft.MicrosoftSolitaireCollection','Microsoft.Microsoft3DViewer',
        'Microsoft.MixedReality.Portal','Microsoft.SkypeApp','Microsoft.XboxSpeechToTextOverlay',
        'Microsoft.Getstarted','Microsoft.Print3D'
    )
    foreach ($a in $both) { Remove-Sel01Appx $a }

    # Clean only (Office box, no gaming) - includes Widgets host + media + mail.
    # GAMING KEEPS: Microsoft.GamingApp, Microsoft.XboxGamingOverlay (Game Bar).
    if ($Global:Sel01Tweaker.Profile -eq 'Clean') {
        foreach ($a in 'MicrosoftWindows.Client.WebExperience','Microsoft.ZuneMusic','Microsoft.ZuneVideo',
                        'Microsoft.WindowsCommunicationsApps','Microsoft.MicrosoftStickyNotes',
                        'Microsoft.BingNews','MicrosoftWindows.CrossDevice',
                        'Microsoft.GamingApp','Microsoft.XboxGamingOverlay') {
            Remove-Sel01Appx $a
        }
    }
}


# ----- bundled: 17-Win10.ps1 -----
# ============================================================================
#  Module 17 - Windows 10 specific  (only runs on Win10: -not IsWin11)
#  Tweaks that are Win10-only or use Win10 paths a Win11-era tool would miss.
#  All via Set-Reg / Set-ServiceStart -> snapshotted + reversible. No-ops on
#  Win11 (the whole module is gated off). Researched, low-risk, both profiles.
# ============================================================================

function Invoke-Module-Win10 {
    Write-Log '=== Module: Windows 10 specific ===' 'STEP'

    if ($Global:Sel01Tweaker.IsWin11) {
        Write-Log 'Windows 11 erkannt - Win10-Modul uebersprungen' 'INFO'
        return
    }

    # --- Classic Cortana off ---------------------------------------------
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\Windows Search' 'AllowCortana' DWord 0 -Note 'Cortana off (Win10)'

    # --- Bing / web results in Win10 Start search off --------------------
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\Windows Search' 'ConnectedSearchUseWeb' DWord 0 -Note 'Web search in Start off (Win10)'
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\Windows Search' 'DisableWebSearch'      DWord 1
    Set-Reg 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Search' 'BingSearchEnabled'       DWord 0
    Set-Reg 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Search' 'CortanaConsent'          DWord 0

    # --- Taskbar clutter: My People + sync-provider ads ------------------
    Set-Reg 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\Advanced\People' 'PeopleBand' DWord 0 -Note 'My People taskbar off (Win10)'
    Set-Reg 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\Advanced' 'ShowSyncProviderNotifications' DWord 0 -Note 'Explorer OneDrive/Office ads off (Win10)'

    # --- First-logon animation off (faster first sign-in) ----------------
    Set-Reg 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System' 'EnableFirstLogonAnimation' DWord 0 -Note 'First-logon animation off (Win10)'

    # --- Edge Legacy preload/prelaunch off (no-op if absent) -------------
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\MicrosoftEdge\Main' 'AllowPrelaunch' DWord 0 -Note 'Edge Legacy preload off (Win10)'
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\MicrosoftEdge\TabPreloader' 'AllowTabPreloading' DWord 0

    # --- Win10 diagnostics standard collector service off ----------------
    Set-ServiceStart 'diagnosticshub.standardcollector.service' Disabled -Note 'Diagnostics collector off (Win10)'
}


# ----- bundled: 18-Services.ps1 -----
# ============================================================================
#  Module 18 - Extra services  (research-vetted, ALL Manual - never Disabled)
#  Surveyed from winutil / Optimizer / privacy.sexy / Sophia / O&O and a deep
#  services audit, then adversarially safety-checked. Manual (not Disabled) so
#  anything still demand-starts -> nothing breaks, idle load drops, fully
#  reversible (Set-ServiceStart snapshots the prior Start type). The hard
#  deny-list in Set-ServiceStart still blocks anything security/network core.
# ============================================================================

function Invoke-Module-Services {
    Write-Log '=== Module: Extra services (Manual, vetted) ===' 'STEP'

    $clean = ($Global:Sel01Tweaker.Profile -eq 'Clean')

    # --- Both profiles: diagnostics / legacy-net / niche, all demand-startable
    # InventorySvc = inventory/compat telemetry (runs at idle on a fresh box);
    # BcastDVRUserService = GameDVR broadcast (GameDVR is already off everywhere).
    foreach ($svc in 'WdiServiceHost','WdiSystemHost','lltdsvc','Spectrum',
                      'perceptionsimulation','lmhosts','autotimesvc',
                      'diagnosticshub.standardcollector.service',
                      'InventorySvc','BcastDVRUserService') {
        Set-ServiceStart $svc Manual
    }
    # Cellular modem service: desktops only (laptops/tablets may have WWAN hw).
    if (-not $Global:Sel01Tweaker.IsLaptop) {
        Set-ServiceStart 'WwanSvc' Manual
    }
    Add-Change 'Extra diagnostics/legacy services -> Manual'

    # --- Clean-only: deeper trim of services unused on a home/gaming box -----
    # All Manual: offline-files, storage UI (trigger), ICS/NAT (trigger - WSL2/
    # Hyper-V keep working), Miracast, MTP, printer toasts, inbound RDP, WebDAV,
    # File History, cross-device, peer-name, VPN auto-dial, SSTP, problem-report
    # viewer, event forwarding, encryption plugins, SNMP traps, 802.1X wired,
    # dynamic-lock, smart-card cert, domain logon (no-op off-domain), network
    # discovery, UPnP/DLNA discovery, hardware-detection (AutoPlay).
    if ($clean) {
        foreach ($svc in 'CscService','StorSvc','SharedAccess','WFDSConMgrSvc','WPDBusEnum',
                          'PrintNotify','TermService','SessionEnv','UmRdpService','WebClient',
                          'fhsvc','CDPSvc','p2psvc','p2pimsvc','PNRPsvc','PNRPAutoReg',
                          'RasAuto','SstpSvc','wercplsupport','Wecsvc','WEPHOSTSVC','SNMPTRAP',
                          'dot3svc','NaturalAuthentication','CertPropSvc','Netlogon',
                          'fdPHost','FDResPub','SSDPSRV','upnphost','ShellHWDetection',
                          'iphlpsvc') {
            Set-ServiceStart $svc Manual
        }
        Add-Change 'Clean: deeper unused-service trim -> Manual'
    }
}



# ---------------------------------------------------------------------------
#  Load parts. When bundled into dist\Sel01Tweaker.ps1 the functions already
#  exist, so dot-sourcing is skipped. When running from src\, pull lib+modules.
# ---------------------------------------------------------------------------
if (-not (Get-Command Invoke-Module-Performance -ErrorAction SilentlyContinue)) {
    $root = $PSScriptRoot
    . (Join-Path $root 'lib\Common.ps1')
    . (Join-Path $root 'lib\Backup.ps1')
    . (Join-Path $root 'lib\Ui.ps1')
    Get-ChildItem (Join-Path $root 'modules') -Filter '*.ps1' | Sort-Object Name | ForEach-Object { . $_.FullName }
}

